// Option A: EventSource (GET only)
const source = new EventSource("/chat/stream?session_id=abc");
source.onmessage = (event) => {
  const data = JSON.parse(event.data);
  if (data.type === "token") {
    document.getElementById("output").textContent += data.text;
  } else if (data.type === "done") {
    source.close();
  }
};
source.onerror = () => source.close();

// Option B: fetch + ReadableStream (POST, supports JSON body)
async function streamChat(messages) {
  const resp = await fetch("/chat/stream", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ messages }),
  });

  const reader = resp.body.getReader();
  const decoder = new TextDecoder();
  let buffer = "";

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;

    buffer += decoder.decode(value, { stream: true });
    const lines = buffer.split("\n\n");
    buffer = lines.pop(); // keep incomplete last chunk

    for (const line of lines) {
      if (!line.startsWith("data: ")) continue;
      const data = JSON.parse(line.slice(6));
      if (data.type === "token") {
        appendToken(data.text);
      }
    }
  }
}

import json
import anthropic

client = anthropic.Anthropic()

def stream_and_collect_tool_inputs(
    messages: list[dict],
    tools: list[dict],
) -> list[dict]:
    """Collect fully assembled tool call inputs from a streamed response."""
    tool_calls: list[dict] = []
    buffers: dict[int, str] = {}  # block_index -> json fragment buffer
    block_meta: dict[int, dict] = {}

    with client.messages.stream(
        model="claude-sonnet-5",
        max_tokens=4096,
        messages=messages,
        tools=tools,
    ) as stream:
        for event in stream:
            if event.type == "content_block_start":
                blk = event.content_block
                if blk.type == "tool_use":
                    block_meta[event.index] = {"id": blk.id, "name": blk.name}
                    buffers[event.index] = ""

            elif event.type == "content_block_delta":
                if event.delta.type == "input_json_delta":
                    buffers[event.index] = buffers.get(event.index, "") + event.delta.partial_json

            elif event.type == "content_block_stop":
                if event.index in buffers:
                    meta = block_meta.pop(event.index, {})
                    raw = buffers.pop(event.index, "{}")
                    tool_calls.append({
                        "id": meta["id"],
                        "name": meta["name"],
                        "input": json.loads(raw),
                    })

    return tool_calls
